  5→//! Rail command - reorder Paces within a Heat
  6→//!
  7→//! Supports two modes:
  8→//! - Order mode: replace entire sequence with provided order array
  9→//! - Move mode: relocate a single pace using positioning flags
 10→
 11→use clap::Args;
 12→use std::path::PathBuf;
 13→
 14→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 15→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
 16→
 17→/// Arguments for jjx_rail command
 18→#[derive(Args, Debug)]
 19→pub struct jjrrl_RailArgs {
 20→    /// Path to the Gallops JSON file
 21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 22→    pub file: PathBuf,
 23→
 24→    /// Target Heat identity (Firemark)
 25→    pub firemark: String,
 26→
 27→    /// Legacy positional args - rejected at runtime
 28→    #[arg(trailing_var_arg = true)]
 29→    pub order: Vec<String>,
 30→
 31→    // Move mode arguments
 32→
 33→    /// Coronet to relocate within order - triggers move mode
 34→    #[arg(long, short = 'm')]
 35→    pub r#move: Option<String>,
 36→
 37→    /// Move before specified Coronet
 38→    #[arg(long, conflicts_with_all = ["after", "first", "last"])]
 39→    pub before: Option<String>,
 40→
 41→    /// Move after specified Coronet
 42→    #[arg(long, conflicts_with_all = ["before", "first", "last"])]
 43→    pub after: Option<String>,
 44→
 45→    /// Move to beginning of order
 46→    #[arg(long, conflicts_with_all = ["before", "after", "last"])]
 47→    pub first: bool,
 48→
 49→    /// Move to end of order
 50→    #[arg(long, conflicts_with_all = ["before", "after", "first"])]
 51→    pub last: bool,
 52→}
 53→
 54→/// Execute rail command - reorder Paces within a Heat
 55→pub fn jjrrl_run_rail(args: jjrrl_RailArgs) -> i32 {
 56→    use crate::jjrg_gallops::jjrg_RailArgs as LibRailArgs;
 57→    use crate::jjrn_notch::{jjrn_HeatAction, jjrn_format_heat_message};
 58→
 59→    // Acquire lock FIRST - fail fast if another operation is in progress
 60→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 61→        Ok(l) => l,
 62→        Err(e) => {
 63→            eprintln!("jjx_rail: error: {}", e);
 64→            return 1;
 65→        }
 66→    };
 67→
 68→    let order: Vec<String> = if args.order.len() == 1 && args.order[0].starts_with('[') {
 69→        match serde_json::from_str(&args.order[0]) {
 70→            Ok(v) => v,
 71→            Err(_) => args.order.clone(),
 72→        }
 73→    } else {
 74→        args.order.clone()
 75→    };
 76→
 77→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 78→        Ok(g) => g,
 79→        Err(e) => {
 80→            eprintln!("jjx_rail: error loading Gallops: {}", e);
 81→            return 1;
 82→        }
 83→    };
 84→
 85→    let firemark = args.firemark.clone();
 86→    let move_coronet = args.r#move.clone();
 87→    let move_before = args.before.clone();
 88→    let move_after = args.after.clone();
 89→    let move_first = args.first;
 90→    let move_last = args.last;
 91→    let rail_args = LibRailArgs {
 92→        firemark: args.firemark,
 93→        order,
 94→        move_coronet: args.r#move,
 95→        before: args.before,
 96→        after: args.after,
 97→        first: args.first,
 98→        last: args.last,
 99→    };
100→
101→    match gallops.jjrg_rail(rail_args) {
102→        Ok(new_order) => {
103→            // Compute descriptive subject for commit message
104→            let subject = if let Some(ref moved) = move_coronet {
105→                // Move mode: describe where the pace was moved
106→                let target = if move_first { "to first".to_string() }
107→                    else if move_last { "to last".to_string() }
108→                    else if let Some(ref b) = move_before { format!("before {}", b) }
109→                    else if let Some(ref a) = move_after { format!("after {}", a) }
110→                    else { "???".to_string() };
111→                format!("moved {} {}", moved, target)
112→            } else {
113→                // Order mode: list the new order
114→                format!("order: {}", new_order.join(", "))
115→            };
116→
117→            let fm = Firemark::jjrf_parse(&firemark).expect("rail given invalid firemark");
118→            let message = jjrn_format_heat_message(&fm, jjrn_HeatAction::Rail, &subject);
119→
120→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
121→                Ok(hash) => {
122→                    eprintln!("jjx_rail: committed {}", &hash[..8]);
123→                }
124→                Err(e) => {
125→                    eprintln!("jjx_rail: error: {}", e);
126→                    return 1;
127→                }
128→            }
129→
130→            for coronet in new_order {
131→                println!("{}", coronet);
132→            }
133→            0
134→        }
135→        Err(e) => {
136→            eprintln!("jjx_rail: error: {}", e);
137→            1
138→        }
139→    }
140→    // lock released here
141→}
